var MDM_MCP_URL = process.env.MDM_MCP_URL || "http://localhost:5050/mcp";
async function callMdmTool(toolName, args) {
  const payload = {
    jsonrpc: "2.0",
    id: Date.now(),
    method: "tools/call",
    params: { name: toolName, arguments: args }
  };
  const response = await fetch(MDM_MCP_URL, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload)
  });
  if (!response.ok) {
    throw new Error(
      `MDM MCP server returned ${response.status}: ${await response.text()}`
    );
  }
  const body3 = await response.json();
  if (body3.error) {
    throw new Error(`MDM MCP error: ${body3.error.message}`);
  }
  const text = body3.result?.content?.[0]?.text;
  if (!text) {
    throw new Error("No content in MDM MCP response");
  }
  return JSON.parse(text);
}
async function callKqlm(monitoringAccount, metricNamespace, query2, startTime2, endTime) {
  const result = await callMdmTool("KqlmQuery", {
    monitoringAccount,
    metricNamespace,
    startTime: startTime2,
    endTime,
    finalKqlmQuery: query2
  });
  if (!result.Success || !result.Result || result.Result.length === 0) {
    return null;
  }
  const raw = Array.isArray(result.Result) ? result.Result[0] : result.Result;
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}
