  lines.push("### Throttling & Drops");
  lines.push(
    "| Panel | Metric | Status |",
    "| --- | --- | --- |"
  );
  for (const r of throttleResults) {
    const icon = r.status === "ok" ? "\u2705" : r.status === "warning" ? "\u26A0\uFE0F" : "\u2139\uFE0F";
    lines.push(`| ${r.panel} | \`${r.metric}\` | ${icon} ${r.summary} |`);
  }
  lines.push("", "### Volume & Limits");
