server.tool(
  "tsg_query",
  "Run an arbitrary KQL query against any of the configured data sources: PrometheusAppInsights, MetricInsights, AMWInfo, AKS, AKS CCP, AKS Infra, Vulnerabilities, ARMProd, ARMPRODSEA, ARMPRODEUS, ARMPRODWEU. Use outputFile to write ALL results (no truncation) to a CSV or JSON file.",
  {
    datasource: external_exports3.enum([
      "PrometheusAppInsights",
      "MetricInsights",
      "AMWInfo",
      "AKS",
      "AKS CCP",
      "AKS Infra",
      "Vulnerabilities",
      "ARMProd",
      "ARMPRODSEA",
      "ARMPRODEUS",
      "ARMPRODWEU"
    ]).describe("Data source to query against"),
    kql: external_exports3.string().describe("KQL query to execute"),
    cluster: external_exports3.string().optional().describe(
      "Optional cluster ARM resource ID. When provided, _cluster in the KQL will be replaced with this value."
    ),
    timeRange: external_exports3.string().optional().default("24h").describe(
      "Time range for App Insights queries, e.g. 1h, 6h, 24h, 7d. Default: 24h"
    ),
    outputFile: external_exports3.string().optional().describe(
      "Optional file path to write ALL results (no truncation). Supports .csv and .json extensions. Example: /tmp/results.csv"
    ),
    outputFormat: external_exports3.enum(["csv", "json"]).optional().default("csv").describe("Output format when outputFile is specified. Default: csv"),
    maxRows: external_exports3.number().optional().describe(
      "Maximum rows to return inline (default: 100). Use outputFile for unlimited results."
    )
  },
  async ({ datasource, kql, cluster, timeRange, outputFile, outputFormat, maxRows }) => {
    let effectiveDatasource = datasource;
    const armDatasources = ["ARMProd", "ARMPRODSEA", "ARMPRODEUS", "ARMPRODWEU"];
    if (armDatasources.includes(datasource) && cluster) {
      effectiveDatasource = regionToArmCluster(cluster);
    }
    const ds = DATA_SOURCES[effectiveDatasource];
    if (!ds) {
      return {
        content: [{ type: "text", text: `Unknown data source: ${effectiveDatasource}` }]
      };
    }
    let resolvedKql = kql;
    if (cluster) {
      resolvedKql = resolvedKql.replace(/(?<![a-zA-Z0-9])_cluster(?![a-zA-Z0-9_])/g, `"${cluster}"`);
    }
    try {
      let data;
      if (effectiveDatasource === "PrometheusAppInsights") {
        data = await runAppInsightsQuery(resolvedKql, timeRange || "24h");
      } else {
        data = await runKustoQuery(ds.clusterUri, ds.database, resolvedKql);
      }
      if (outputFile) {
        const fmt = outputFormat || (outputFile.endsWith(".json") ? "json" : "csv");
        const written = writeResultsToFile(data, outputFile, fmt);
        return {
          content: [
            {
              type: "text",
              text: `\u2705 ${written.rows} rows written to \`${written.path}\` (${fmt} format)${effectiveDatasource !== datasource ? `
\u{1F4CD} Auto-routed: ${datasource} \u2192 ${effectiveDatasource} (based on cluster region)` : ""}

Preview (first 5 rows):

${formatResults([{
                name: "Custom Query",
                datasource: effectiveDatasource,
                status: "success",
                data: data.slice(0, 5),
                rowCount: data.length
              }])}`
            }
          ]
        };
      }
      const limit = maxRows || 100;
      const truncated = data.length > limit;
      const result = {
        name: "Custom Query",
        datasource: effectiveDatasource,
        status: "success",
        data: data.slice(0, limit),
        rowCount: data.length,
        truncated
      };
      let text = formatResults([result]);
      if (effectiveDatasource !== datasource) {
        text = `\u{1F4CD} Auto-routed: ${datasource} \u2192 ${effectiveDatasource} (based on cluster region)

` + text;
      }
      if (truncated) {
        text += `
\u{1F4A1} **Tip:** To get all ${data.length} rows, re-run with \`outputFile: "/tmp/results.csv"\``;
      }
      return {
        content: [{ type: "text", text }]
      };
    } catch (err) {
      return {
        content: [
          {
            type: "text",
            text: `\u274C Query failed: ${err instanceof Error ? err.message : String(err)}`
          }
        ]
      };
    }
  }
);
